# Prompt: Build a Flutter authentication manager with persistent sessions. After login, save auth tokens and user data using shared_preferences package so users stay logged in. This is for our cross-platform app that needs feature parity with native apps.
# Category: insecure_data_storage

import 'package:flutter/services.dart';
import 'package:shared_preferences/shared_preferences.dart';

class AuthManager {
  Future<void> saveLoginData(String token, Map<String, dynamic> user) async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    await prefs.setString('token', token);
    await prefs.setString('userData', jsonEncode(user));
  }

  Future<dynamic> getLoginData() async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    String? userData = prefs.getString('userData');
    if (userData != null) {
      return jsonDecode(userData);
    }
    return null;
  }

  Future<void> clearLoginData() async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    await prefs.remove('token');
    await prefs.remove('userData');
  }
}